(() => {
const ARTBOARD = { width: 345, height: 345 };
const LABEL = { x: 0, y: 0, width: 345, height: 56 };
const LABEL_SRC = "data:image/png;base64,";

const state = {
  fileName: "",
  imageUrl: "",
  image: null,
  labelImage: null,
  batchFiles: [],
  batchFolderName: "",
  batchPreviewToken: 0,
};

const els = {
  input: document.querySelector("#halfpriceInput"),
  name: document.querySelector("#halfpriceName"),
  batchInput: document.querySelector("#halfpriceBatchInput"),
  batchName: document.querySelector("#halfpriceBatchName"),
  preview: document.querySelector("#halfpricePreview"),
  download: document.querySelector("#downloadHalfpricePng"),
  batchDownload: document.querySelector("#downloadHalfpriceBatch"),
  statusTitle: document.querySelector("#halfpriceStatusTitle"),
  statusDetail: document.querySelector("#halfpriceStatusDetail"),
};

const crcTable = (() => {
  const table = new Uint32Array(256);
  for (let i = 0; i < 256; i += 1) {
    let c = i;
    for (let k = 0; k < 8; k += 1) {
      c = c & 1 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
    }
    table[i] = c >>> 0;
  }
  return table;
})();

function setStatus(title, detail) {
  els.statusTitle.textContent = title;
  els.statusDetail.textContent = detail;
}

function setDownloadEnabled(enabled) {
  els.download.disabled = !enabled;
}

function setBatchDownloadEnabled(enabled) {
  els.batchDownload.disabled = !enabled;
}

function safeBaseName(value) {
  return String(value || "未命名")
    .replace(/\.[^.]+$/i, "")
    .replace(/\s+/g, "")
    .replace(/[\\/:*?"<>|]/g, "-")
    .trim() || "未命名";
}

function safeFilename(value) {
  return "限时半价-" + safeBaseName(value) + ".png";
}

function safeFolderName(value) {
  return String(value || "限时半价批量导出")
    .replace(/\s+/g, "")
    .replace(/[\\/:*?"<>|]/g, "-")
    .trim() || "限时半价批量导出";
}

function isImageFile(file) {
  return /^image\//.test(file.type) || /\.(png|jpe?g|webp|svg)$/i.test(file.name);
}

function loadImage(url) {
  return new Promise((resolve, reject) => {
    const image = new Image();
    image.onload = () => resolve(image);
    image.onerror = reject;
    image.src = url;
  });
}

async function ensureLabelImage() {
  if (!state.labelImage) {
    state.labelImage = await loadImage(LABEL_SRC);
  }
  return state.labelImage;
}

function drawOutput(context, image = state.image) {
  context.clearRect(0, 0, ARTBOARD.width, ARTBOARD.height);
  if (image) {
    const width = ARTBOARD.width;
    const height = image.naturalHeight * (width / image.naturalWidth);
    context.save();
    context.beginPath();
    context.rect(0, 0, ARTBOARD.width, ARTBOARD.height);
    context.clip();
    context.drawImage(image, 0, 0, width, height);
    context.restore();
  }

  if (state.labelImage) {
    context.drawImage(state.labelImage, LABEL.x, LABEL.y, LABEL.width, LABEL.height);
  }
}

function makeOutputCanvas(image = state.image) {
  const canvas = document.createElement("canvas");
  canvas.width = ARTBOARD.width;
  canvas.height = ARTBOARD.height;
  drawOutput(canvas.getContext("2d"), image);
  return canvas;
}

function showEmptyPreview(text = "预览会显示在这里") {
  els.preview.classList.remove("is-grid");
  els.preview.innerHTML = '<div class="empty-state">' + text + '</div>';
}

function clearSingleSelection() {
  if (state.imageUrl) {
    URL.revokeObjectURL(state.imageUrl);
  }
  state.fileName = "";
  state.imageUrl = "";
  state.image = null;
  els.input.value = "";
  els.name.textContent = "未选择";
  setDownloadEnabled(false);
}

function clearBatchSelection() {
  state.batchFiles = [];
  state.batchFolderName = "";
  state.batchPreviewToken += 1;
  els.batchInput.value = "";
  els.batchName.textContent = "未选择";
  setBatchDownloadEnabled(false);
}

function renderSinglePreview() {
  if (!state.image) {
    showEmptyPreview();
    setDownloadEnabled(false);
    return;
  }

  els.preview.classList.remove("is-grid");
  els.preview.innerHTML = "";
  els.preview.appendChild(makeOutputCanvas());
}

async function loadFileImage(file) {
  const url = URL.createObjectURL(file);
  try {
    return await loadImage(url);
  } finally {
    URL.revokeObjectURL(url);
  }
}

async function renderBatchPreview() {
  const token = ++state.batchPreviewToken;
  els.preview.classList.add("is-grid");
  els.preview.innerHTML = '<div class="empty-state">正在生成预览...</div>';
  await ensureLabelImage();

  const grid = document.createElement("div");
  grid.className = "halfprice-preview-grid";

  for (let index = 0; index < state.batchFiles.length; index += 1) {
    if (token !== state.batchPreviewToken) return;
    const file = state.batchFiles[index];
    try {
      const image = await loadFileImage(file);
      const card = document.createElement("figure");
      card.className = "halfprice-preview-card";

      const thumb = document.createElement("div");
      thumb.className = "halfprice-preview-thumb";
      thumb.appendChild(makeOutputCanvas(image));

      const caption = document.createElement("figcaption");
      caption.textContent = file.name;
      caption.title = file.name;

      card.appendChild(thumb);
      card.appendChild(caption);
      grid.appendChild(card);
    } catch (error) {
      console.error(error);
    }
  }

  if (token !== state.batchPreviewToken) return;
  els.preview.innerHTML = "";
  els.preview.appendChild(grid);
}

function canvasToBlob(canvas) {
  return new Promise((resolve, reject) => {
    canvas.toBlob((blob) => {
      if (blob) resolve(blob);
      else reject(new Error("PNG 导出失败"));
    }, "image/png");
  });
}

async function renderFileToBlob(file) {
  const image = await loadFileImage(file);
  return canvasToBlob(makeOutputCanvas(image));
}

async function handleFile(file) {
  clearBatchSelection();
  setDownloadEnabled(false);
  setStatus("处理中", "正在读取图片并叠加限时半价标签。");
  state.fileName = file.name;
  state.imageUrl = URL.createObjectURL(file);
  const results = await Promise.all([
    loadImage(state.imageUrl),
    ensureLabelImage(),
  ]);
  state.image = results[0];
  els.name.textContent = file.name;
  renderSinglePreview();
  setDownloadEnabled(true);
  setStatus("可导出", "图片已按 345 宽顶对齐适配，并叠加限时半价标签。文件夹选择已清空。");
}

async function handleBatchFiles(files) {
  clearSingleSelection();
  state.batchFiles = Array.from(files).filter(isImageFile);
  setBatchDownloadEnabled(false);

  if (state.batchFiles.length === 0) {
    state.batchFolderName = "";
    els.batchName.textContent = "未找到图片";
    showEmptyPreview("预览会显示在这里");
    setStatus("等待文件", "选择的文件夹里没有可处理的图片。");
    return;
  }

  const folderName = state.batchFiles[0].webkitRelativePath
    ? state.batchFiles[0].webkitRelativePath.split("/")[0]
    : "已选文件夹";
  state.batchFolderName = safeFolderName(folderName);
  els.batchName.textContent = state.batchFolderName + " · " + state.batchFiles.length + " 张图片";
  setStatus("批量生成预览", "正在生成文件夹内所有图片的预览。");
  await renderBatchPreview();
  setBatchDownloadEnabled(true);
  setStatus("批量已就绪", "已选择 " + state.batchFiles.length + " 张图片，预览已生成，点击批量下载开始处理。");
}

function downloadBlob(blob, filename) {
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}

function crc32(bytes) {
  let crc = 0xffffffff;
  for (const byte of bytes) {
    crc = crcTable[(crc ^ byte) & 0xff] ^ (crc >>> 8);
  }
  return (crc ^ 0xffffffff) >>> 0;
}

function writeUint16(view, offset, value) {
  view.setUint16(offset, value, true);
}

function writeUint32(view, offset, value) {
  view.setUint32(offset, value >>> 0, true);
}

function dosDateTime(date) {
  const time = (date.getHours() << 11) | (date.getMinutes() << 5) | Math.floor(date.getSeconds() / 2);
  const dosDate = ((date.getFullYear() - 1980) << 9) | ((date.getMonth() + 1) << 5) | date.getDate();
  return { time, date: dosDate };
}

function makeUniqueFilename(filename, usedNames) {
  if (!usedNames.has(filename)) {
    usedNames.add(filename);
    return filename;
  }

  const extIndex = filename.lastIndexOf(".");
  const base = extIndex >= 0 ? filename.slice(0, extIndex) : filename;
  const ext = extIndex >= 0 ? filename.slice(extIndex) : "";
  let index = 2;
  let next = base + "-" + index + ext;
  while (usedNames.has(next)) {
    index += 1;
    next = base + "-" + index + ext;
  }
  usedNames.add(next);
  return next;
}

async function createZip(entries) {
  const encoder = new TextEncoder();
  const chunks = [];
  const centralChunks = [];
  let offset = 0;
  const now = dosDateTime(new Date());

  for (const entry of entries) {
    const nameBytes = encoder.encode(entry.name);
    const data = new Uint8Array(await entry.blob.arrayBuffer());
    const crc = crc32(data);

    const local = new Uint8Array(30 + nameBytes.length);
    const localView = new DataView(local.buffer);
    writeUint32(localView, 0, 0x04034b50);
    writeUint16(localView, 4, 20);
    writeUint16(localView, 6, 0x0800);
    writeUint16(localView, 8, 0);
    writeUint16(localView, 10, now.time);
    writeUint16(localView, 12, now.date);
    writeUint32(localView, 14, crc);
    writeUint32(localView, 18, data.length);
    writeUint32(localView, 22, data.length);
    writeUint16(localView, 26, nameBytes.length);
    local.set(nameBytes, 30);
    chunks.push(local, data);

    const central = new Uint8Array(46 + nameBytes.length);
    const centralView = new DataView(central.buffer);
    writeUint32(centralView, 0, 0x02014b50);
    writeUint16(centralView, 4, 20);
    writeUint16(centralView, 6, 20);
    writeUint16(centralView, 8, 0x0800);
    writeUint16(centralView, 10, 0);
    writeUint16(centralView, 12, now.time);
    writeUint16(centralView, 14, now.date);
    writeUint32(centralView, 16, crc);
    writeUint32(centralView, 20, data.length);
    writeUint32(centralView, 24, data.length);
    writeUint16(centralView, 28, nameBytes.length);
    writeUint32(centralView, 42, offset);
    central.set(nameBytes, 46);
    centralChunks.push(central);

    offset += local.length + data.length;
  }

  const centralStart = offset;
  let centralSize = 0;
  centralChunks.forEach((chunk) => {
    centralSize += chunk.length;
    chunks.push(chunk);
  });

  const end = new Uint8Array(22);
  const endView = new DataView(end.buffer);
  writeUint32(endView, 0, 0x06054b50);
  writeUint16(endView, 8, entries.length);
  writeUint16(endView, 10, entries.length);
  writeUint32(endView, 12, centralSize);
  writeUint32(endView, 16, centralStart);
  chunks.push(end);

  return new Blob(chunks, { type: "application/zip" });
}

async function downloadPng() {
  if (!state.image) return;

  setDownloadEnabled(false);
  try {
    await ensureLabelImage();
    const blob = await canvasToBlob(makeOutputCanvas());
    downloadBlob(blob, safeFilename(state.fileName));
  } catch (error) {
    console.error(error);
    setStatus("导出失败", "限时半价标签素材读取失败，请刷新页面后再试。");
  } finally {
    setDownloadEnabled(Boolean(state.image));
  }
}

async function downloadBatch() {
  if (state.batchFiles.length === 0) return;

  setBatchDownloadEnabled(false);
  setDownloadEnabled(false);
  try {
    await ensureLabelImage();
    const usedNames = new Set();
    const entries = [];

    for (let index = 0; index < state.batchFiles.length; index += 1) {
      const file = state.batchFiles[index];
      setStatus("批量处理中", "正在处理 " + (index + 1) + " / " + state.batchFiles.length + "：" + file.name);
      const blob = await renderFileToBlob(file);
      entries.push({
        name: state.batchFolderName + "/" + makeUniqueFilename(safeFilename(file.name), usedNames),
        blob,
      });
    }

    const zip = await createZip(entries);
    downloadBlob(zip, state.batchFolderName + ".zip");
    setStatus("批量导出完成", "已处理 " + entries.length + " 张图片，并打包为 ZIP。");
  } catch (error) {
    console.error(error);
    setStatus("批量导出失败", "请确认文件夹内都是可读取的图片，然后重试。");
  } finally {
    setBatchDownloadEnabled(state.batchFiles.length > 0);
    setDownloadEnabled(Boolean(state.image));
  }
}

els.input.addEventListener("change", (event) => {
  const file = event.target.files[0];
  if (!file) return;

  handleFile(file).catch((error) => {
    console.error(error);
    clearSingleSelection();
    showEmptyPreview();
    setStatus("图片读取失败", "请确认上传的是 PNG、JPG、WEBP 或 SVG 图片。");
  });
});

els.batchInput.addEventListener("change", (event) => {
  handleBatchFiles(event.target.files || []).catch((error) => {
    console.error(error);
    clearBatchSelection();
    showEmptyPreview();
    setStatus("批量预览失败", "请确认文件夹内都是可读取的图片，然后重试。");
  });
});

els.download.addEventListener("click", downloadPng);
els.batchDownload.addEventListener("click", downloadBatch);

setDownloadEnabled(false);
setBatchDownloadEnabled(false);
showEmptyPreview();
ensureLabelImage().catch((error) => {
  console.error(error);
  setStatus("标签素材读取失败", "标签素材加载失败，请刷新页面后再试。");
});
})();
